import { useState, useEffect, useCallback, useMemo } from "react";

// ─── Default Hanzi Data ───────────────────────────────────────────────
const DEFAULT_HANZI_DATA = [
  // 言部
  { char: "記", words: ["記錄", "記憶", "日記"], zhuyin: "ㄐㄧˋ", pinyin: "jì", radical: "言" },
  { char: "論", words: ["討論", "論文", "言論"], zhuyin: "ㄌㄨㄣˋ", pinyin: "lùn", radical: "言" },
  { char: "詞", words: ["詞語", "歌詞", "詞彙"], zhuyin: "ㄘˊ", pinyin: "cí", radical: "言" },
  { char: "訪", words: ["訪問", "採訪", "拜訪"], zhuyin: "ㄈㄤˇ", pinyin: "fǎng", radical: "言" },
  { char: "評", words: ["評價", "評論", "批評"], zhuyin: "ㄆㄧㄥˊ", pinyin: "píng", radical: "言" },
  { char: "誠", words: ["誠實", "誠懇", "真誠"], zhuyin: "ㄔㄥˊ", pinyin: "chéng", radical: "言" },
  { char: "謝", words: ["感謝", "謝謝", "道謝"], zhuyin: "ㄒㄧㄝˋ", pinyin: "xiè", radical: "言" },
  { char: "識", words: ["認識", "知識", "常識"], zhuyin: "ㄕˋ", pinyin: "shì", radical: "言" },
  { char: "誤", words: ["錯誤", "誤會", "失誤"], zhuyin: "ㄨˋ", pinyin: "wù", radical: "言" },
  { char: "謙", words: ["謙虛", "謙讓", "謙遜"], zhuyin: "ㄑㄧㄢ", pinyin: "qiān", radical: "言" },
  { char: "諒", words: ["原諒", "體諒", "諒解"], zhuyin: "ㄌㄧㄤˋ", pinyin: "liàng", radical: "言" },
  { char: "議", words: ["會議", "建議", "議題"], zhuyin: "ㄧˋ", pinyin: "yì", radical: "言" },
  { char: "譯", words: ["翻譯", "譯文", "口譯"], zhuyin: "ㄧˋ", pinyin: "yì", radical: "言" },
  // 心部
  { char: "想", words: ["想像", "思想", "夢想"], zhuyin: "ㄒㄧㄤˇ", pinyin: "xiǎng", radical: "心" },
  { char: "感", words: ["感覺", "感動", "感謝"], zhuyin: "ㄍㄢˇ", pinyin: "gǎn", radical: "心" },
  { char: "慮", words: ["考慮", "顧慮", "憂慮"], zhuyin: "ㄌㄩˋ", pinyin: "lǜ", radical: "心" },
  { char: "態", words: ["態度", "狀態", "姿態"], zhuyin: "ㄊㄞˋ", pinyin: "tài", radical: "心" },
  { char: "慣", words: ["習慣", "慣例", "慣用"], zhuyin: "ㄍㄨㄢˋ", pinyin: "guàn", radical: "心" },
  { char: "愁", words: ["憂愁", "發愁", "愁苦"], zhuyin: "ㄔㄡˊ", pinyin: "chóu", radical: "心" },
  { char: "悟", words: ["領悟", "覺悟", "醒悟"], zhuyin: "ㄨˋ", pinyin: "wù", radical: "心" },
  { char: "憶", words: ["記憶", "回憶", "追憶"], zhuyin: "ㄧˋ", pinyin: "yì", radical: "心" },
