      background: var(--paper);
    }

    .import-textarea:focus {
      outline: none;
      border-color: var(--accent);
    }

    .import-stats {
      margin-top: 16px;
      padding-top: 16px;
      border-top: 1px solid var(--mist);
      font-size: 0.95rem;
      color: #666;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }

    .btn-danger {
      background: none;
      border: 1px solid var(--wrong);
      color: var(--wrong);
      padding: 6px 12px;
      border-radius: 6px;
      cursor: pointer;
      font-family: inherit;
      transition: all 0.2s;
    }

    .btn-danger:hover {
      background: var(--wrong);
      color: white;
    }

    /* ─── Browse ─── */
    .browse-tabs {
      display: flex;
      overflow-x: auto;
      gap: 8px;
      padding: 8px 0;
      -webkit-overflow-scrolling: touch;
      scrollbar-width: none;
    }

    .browse-tabs::-webkit-scrollbar { display: none; }

    .browse-tab {
      flex-shrink: 0;
      padding: 8px 16px;
      border-radius: 999px;
      border: 1.5px solid var(--mist);
      background: white;
      font-size: 1.05rem;
      cursor: pointer;
      transition: all 0.2s;
      font-family: inherit;
    }

    .browse-tab.active {
      background: var(--ink);
      color: white;
      border-color: var(--ink);
    }

    .card-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
      gap: 12px;
      margin-top: 16px;
    }

    .char-card {
      background: white;
      border-radius: 12px;
      padding: 20px 12px;
      text-align: center;
      cursor: pointer;
      transition: all 0.3s;
      border: 1.5px solid var(--cloud);
      position: relative;
    }

    .char-card:hover {
      transform: translateY(-3px);
      box-shadow: 0 8px 24px var(--shadow);
    }

    .char-card .big-char {
      font-size: 3.2rem;
      color: var(--ink);
      line-height: 1.2;
    }

    .char-card .card-zhuyin {
      font-size: 1.15rem;
      color: var(--accent);
      margin-top: 4px;
    }

    .char-card .card-pinyin {
      font-size: 0.9rem;
      color: #999;
      margin-top: 2px;
    }

    .char-card .card-words {
      font-size: 0.9rem;
      color: #777;
      margin-top: 8px;
      line-height: 1.6;
    }

    .char-card.flipped {
      background: var(--ink);
    }

    .char-card.flipped .big-char { color: var(--gold); }
    .char-card.flipped .card-zhuyin { color: #ff7675; }
    .char-card.flipped .card-pinyin { color: #dfe6e9; }
    .char-card.flipped .card-words { color: #b2bec3; }

    /* ─── Quiz & Other Utils ─── (Skipped duplicates for brevity, standard definitions apply here) */
    .quiz-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px; position: relative; }
    .quiz-progress { font-size: 0.95rem; color: #888; }
    .quiz-score { display: flex; gap: 16px; font-size: 1rem; }
    .score-item { display: flex; align-items: center; gap: 4px; }
    .progress-bar { width: 100%; height: 4px; background: var(--cloud); border-radius: 2px; margin-bottom: 24px; overflow: hidden; }
    .progress-fill { height: 100%; background: linear-gradient(90deg, var(--accent), var(--gold)); border-radius: 2px; transition: width 0.4s ease; }

    .quiz-card { background: white; border-radius: 20px; padding: 40px 24px; text-align: center; margin-bottom: 24px; position: relative; overflow: hidden; animation: slideIn 0.3s ease; }
    @keyframes slideIn { from { opacity: 0; transform: translateX(30px); } to { opacity: 1; transform: translateX(0); } }
    .quiz-card .prompt-label { font-size: 0.95rem; color: #aaa; letter-spacing: 2px; margin-bottom: 16px; }
    .quiz-card .prompt-char { font-size: 5rem; color: var(--ink); line-height: 1.1; }
    .quiz-card .prompt-zhuyin { font-size: 2.2rem; color: var(--accent); font-weight: 700; }
    .quiz-card .prompt-word { font-size: 3.2rem; color: var(--ink); letter-spacing: 4px; }
    .quiz-card .hint-text { font-size: 1rem; color: #bbb; margin-top: 12px; }

    .options-grid { display: grid; grid-template-columns: 1fr; gap: 12px; }
    .option-btn { padding: 18px; border-radius: 14px; border: 2px solid var(--mist); background: white; font-family: inherit; font-size: 1.5rem; cursor: pointer; transition: all 0.2s; }
    .option-btn:hover:not(.disabled) { border-color: var(--accent); background: #fff5f5; transform: scale(1.02); }
    .option-btn.correct-opt { border-color: var(--correct); background: #e8fdf0; color: var(--correct); animation: popCorrect 0.3s ease; }
    @keyframes popCorrect { 0% { transform: scale(1); } 50% { transform: scale(1.05); } 100% { transform: scale(1); } }
    .option-btn.wrong-opt { border-color: var(--wrong); background: #fde8e8; color: var(--wrong); animation: shake 0.3s ease; }
    @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-6px); } 75% { transform: translateX(6px); } }
    .option-btn.disabled { cursor: default; opacity: 0.6; }
    .option-btn.reveal-correct { border-color: var(--correct); background: #e8fdf0; }

    /* Result */
    .result-card { background: white; border-radius: 20px; padding: 48px 24px; text-align: center; }
    .result-emoji { font-size: 4rem; margin-bottom: 16px; }
    .result-card h2 { font-size: 2rem; margin-bottom: 8px; }
    .result-score { font-size: 3.5rem; font-weight: 900; color: var(--accent); margin: 16px 0; font-family: 'Noto Serif TC', serif; }
    .result-detail { font-size: 1.05rem; color: #777; margin-bottom: 24px; }
    .result-actions { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; }

    .btn-primary { padding: 12px 28px; border-radius: 999px; border: none; background: var(--accent); color: white; font-family: inherit; font-size: 1.1rem; font-weight: 600; cursor: pointer; transition: all 0.2s; }
    .btn-primary:hover { background: var(--accent2); transform: translateY(-2px); }
    .btn-secondary { padding: 12px 28px; border-radius: 999px; border: 2px solid var(--ink); background: white; color: var(--ink); font-family: inherit; font-size: 1.1rem; font-weight: 600; cursor: pointer; transition: all 0.2s; }
    .btn-secondary:hover { background: var(--ink); color: white; }

    .streak-badge { display: inline-flex; align-items: center; gap: 4px; padding: 4px 12px; background: linear-gradient(135deg, #ff9a56, #ff6b6b); color: white; border-radius: 999px; font-size: 0.9rem; animation: streakPop 0.3s ease; }
    @keyframes streakPop { 0% { transform: scale(0.8); } 50% { transform: scale(1.15); } 100% { transform: scale(1); } }
  `;

  // ─── Render ──────────────────────────────────────────────────────────
  return (
    <>
      <style>{css}</style>
      <div className="app">
        {/* ═══ HOME ═══ */}
        {screen === "home" && (
          <>
            <div className="header">
              <h1>漢字高手</h1>
              <div className="subtitle">108 課綱 · 內建 {DEFAULT_HANZI_DATA.length} 字 + 自訂 {customData.length} 字</div>
            </div>

            <div className="home-grid">
              <div className="mode-card" onClick={() => setScreen("browse")}>
                <span className="mode-tag tag-dark">瀏覽</span>
                <div className="mode-icon">📖</div>
                <h3>字卡瀏覽</h3>
                <p>按部首分類瀏覽所有漢字，含注音、拼音與造詞</p>
              </div>

              <div className="mode-card" onClick={() => startQuiz(1)}>
                <span className="mode-tag tag-red">測驗一</span>
                <div className="mode-icon">👀</div>
                <h3>看漢字 → 選注音</h3>
                <p>看到漢字，從三個注音中選出正確的讀音</p>
              </div>

              <div className="mode-card" onClick={() => startQuiz(2)}>
                <span className="mode-tag tag-green">測驗二</span>
                <div className="mode-icon">👂</div>
                <h3>看注音 → 選漢字</h3>
                <p>看到注音，從三個漢字中選出正確的字</p>
              </div>

              <div className="mode-card" onClick={() => startQuiz(3)}>
                <span className="mode-tag tag-gold">測驗三</span>
                <div className="mode-icon">✏️</div>
                <h3>造詞填空</h3>
                <p>詞語中缺一個字，從三個漢字中選出正確的填入</p>
              </div>

              <div className="mode-card" onClick={() => setScreen("import")}>
                <span className="mode-tag tag-purple">進階</span>
                <div className="mode-icon">➕</div>
                <h3>擴充自訂題庫</h3>
                <p>將生字表或課本重點字大量匯入題庫中</p>
              </div>
            </div>

            <div className="radical-section">
              <h4>
                目前篩選字數 <span className="count-badge">{filteredData.length}/{hanziData.length}</span>
                <span className="chip-actions">
                  <button onClick={selectAll}>全選</button>
                  <button onClick={clearAll}>清除</button>
                </span>
              </h4>
              <div className="radical-chips">
                {allRadicals.map(r => (
                  <span
                    key={r}
                    className={`radical-chip ${selectedRadicals.has(r) ? "on" : ""}`}
                    onClick={() => toggleRadical(r)}
                  >
                    {r}部
                  </span>
                ))}
              </div>
            </div>
          </>
        )}

        {/* ═══ IMPORT SCREEN ═══ */}
        {screen === "import" && (
          <>
            <div className="header" style={{ position: "relative" }}>
              <button className="back-btn" onClick={() => setScreen("home")}>←</button>
              <h1>匯入自訂字庫</h1>
            </div>

            <div className="import-card">
              <p>請依照下方的格式輸入單字，<b>每行輸入一個字</b>，以英文逗號分隔。<br />造詞若有多個，請用斜線 <code>/</code> 分開。</p>
              <div className="import-code">
                漢字,注音,拼音,造詞1/造詞2,部首<br />
                學,ㄒㄩㄝˊ,xué,學校/學習,子<br />
                習,ㄒㄧˊ,xí,習慣/練習,羽
              </div>

              <textarea
                className="import-textarea"
                placeholder="在此貼上您的字表..."
                value={importText}
                onChange={(e) => setImportText(e.target.value)}
              />

              <button className="btn-primary" style={{ width: "100%" }} onClick={handleImport}>
                確認匯入
              </button>

              <div className="import-stats">
                <span>目前已自訂 {customData.length} 個字</span>
                {customData.length > 0 && (
                  <button className="btn-danger" onClick={handleClearCustom}>清除所有自訂</button>
                )}
              </div>
            </div>
          </>
        )}

        {/* ═══ BROWSE ═══ */}
        {screen === "browse" && (
          <>
            <div className="header" style={{ position: "relative" }}>
              <button className="back-btn" onClick={() => setScreen("home")}>←</button>
              <h1>字卡瀏覽</h1>
            </div>

            <div className="browse-tabs">
              {allRadicals.map(r => (
                <button
                  key={r}
                  className={`browse-tab ${currentBrowseRadical === r ? "active" : ""}`}
                  onClick={() => { setBrowseRadical(r); setFlipCard(null); }}
                >
                  {r}部
                </button>
              ))}
            </div>

            <div className="card-grid">
              {browseCards.map((h, i) => (
                <div
                  key={h.char}
                  className={`char-card ${flipCard === i ? "flipped" : ""}`}
                  onClick={() => setFlipCard(flipCard === i ? null : i)}
                >
                  <div className="big-char">{h.char}</div>
                  <div className="card-zhuyin">{h.zhuyin}</div>
                  <div className="card-pinyin">{h.pinyin}</div>
                  <div className="card-words">{h.words.join("、")}</div>
                </div>
              ))}
            </div>
          </>
        )}

        {/* ═══ QUIZ ═══ */}
        {screen === "quiz" && !showResult && quizPool.length > 0 && currentIdx < quizPool.length && (
          <>
            <div className="header" style={{ position: "relative" }}>
              <button className="back-btn" onClick={() => setScreen("home")}>←</button>
              <h1>
                {mode === 1 ? "看字選音" : mode === 2 ? "看音選字" : "造詞填空"}
              </h1>
            </div>

            <div className="quiz-header">
              <span className="quiz-progress">第 {currentIdx + 1} / {quizPool.length} 題</span>
              <div className="quiz-score">
                {streak >= 2 && (
                  <span className="streak-badge" key={streak}>🔥 {streak} 連對</span>
                )}
                <span className="score-item">✓ {score}</span>
              </div>
            </div>

            <div className="progress-bar">
              <div className="progress-fill" style={{ width: `${((currentIdx) / quizPool.length) * 100}%` }} />
            </div>

            <div className="quiz-card" key={animKey}>
              {mode === 1 && (
                <>
                  <div className="prompt-label">這個字怎麼念？</div>
                  <div className="prompt-char">{quizPool[currentIdx].char}</div>
                  <div className="hint-text">{quizPool[currentIdx].pinyin}</div>
                </>
              )}
              {mode === 2 && (
                <>
                  <div className="prompt-label">這個注音是哪個字？</div>
                  <div className="prompt-zhuyin">{quizPool[currentIdx].zhuyin}</div>
                  <div className="hint-text">{quizPool[currentIdx].pinyin}</div>
                </>
              )}
              {mode === 3 && (
                <>
                  <div className="prompt-label">請選出正確的字填入空格</div>
                  <div className="prompt-word">{wordBlank}</div>
                  <div className="hint-text">{quizPool[currentIdx].zhuyin} · {quizPool[currentIdx].pinyin}</div>
                </>
              )}
            </div>

            <div className="options-grid">
              {options.map((opt, i) => {
                const item = quizPool[currentIdx];
                const correctAnswer = mode === 1 ? item.zhuyin : item.char;
                let cls = "option-btn";
                if (selected !== null) {
                  cls += " disabled";
                  if (opt === selected && correct) cls += " correct-opt";
                  else if (opt === selected && !correct) cls += " wrong-opt";
                  else if (opt === correctAnswer && !correct) cls += " reveal-correct";
                }
                return (
                  <button key={i} className={cls} onClick={() => handleSelect(opt)}>
                    {opt}
                  </button>
                );
              })}
            </div>
          </>
        )}

        {/* ═══ RESULT ═══ */}
        {screen === "quiz" && showResult && (
          <>
            <div className="header" style={{ position: "relative" }}>
              <button className="back-btn" onClick={() => setScreen("home")}>←</button>
              <h1>測驗結果</h1>
            </div>

            <div className="result-card">
              <div className="result-emoji">
                {score / quizPool.length >= 0.9 ? "🏆" : score / quizPool.length >= 0.7 ? "🌟" : score / quizPool.length >= 0.5 ? "💪" : "📚"}
              </div>
              <h2>
                {score / quizPool.length >= 0.9 ? "太厲害了！" : score / quizPool.length >= 0.7 ? "表現很好！" : score / quizPool.length >= 0.5 ? "繼續加油！" : "多練習幾次吧！"}
              </h2>
              <div className="result-score">{score} / {quizPool.length}</div>
              <div className="result-detail">
                正確率 {Math.round((score / quizPool.length) * 100)}%
                {bestStreak >= 2 && ` · 最高連對 ${bestStreak} 題`}
              </div>
              <div className="result-actions">
                <button className="btn-primary" onClick={() => startQuiz(mode)}>再來一次</button>
                <button className="btn-secondary" onClick={() => setScreen("home")}>回首頁</button>
              </div>
            </div>
          </>
        )}
      </div>
    </>
  );
}
